sql:
SELECT AVG(accuracy) AS avg_accuracy
FROM pose_estimation_results
WHERE method_version = '1.0';

SELECT AVG(confidence) AS average_confidence
FROM object_poses
WHERE sensor_id = 1;

SELECT COUNT(*) as high_confidence_estimations
FROM object_poses
WHERE confidence >= 0.8 AND sensor_id = 1;

SELECT AVG(confidence) AS average_confidence
FROM object_poses
WHERE confidence > 0.9;

SELECT pose_id, confidence
   FROM object_poses
   WHERE confidence > 0.98;

external_knowledge:
Pose estimation methods are algorithms used to estimate the position and orientation of objects in 3D space from sensor data; 
Error rates and confidence levels are common metrics used to evaluate the performance of these methods, with lower error rates and higher confidence levels indicating better performance; 
Cumulative distribution values are used to compare the performance of different methods across different environments and sensors.

sql:
SELECT COUNT(*) AS pose_count
FROM object_pose_links
WHERE dataset_id = 1;

SELECT method_name
FROM pose_estimation_methods
WHERE method_complexity = 'high' AND method_accuracy > 0.9;

SELECT pose_id
FROM object_poses
WHERE confidence = (SELECT MAX(confidence) FROM object_poses);

SELECT object_id, COUNT(pose_id) AS pose_count
FROM object_poses
GROUP BY object_id;

SELECT method_complexity, COUNT(*) AS method_count
FROM pose_estimation_methods
GROUP BY method_complexity;
